// 旅智星 - 方案页
import { useState, useMemo } from "react";
import { useParams, useNavigate, Link } from "react-router-dom";
import {
  ArrowLeft,
  Printer,
  Share2,
  RefreshCw,
  MapPin,
  Clock,
  Ticket,
  UtensilsCrossed,
  Hotel as HotelIcon,
  Route as RouteIcon,
  Check,
  Sparkles,
  Calendar,
  Users,
  Wallet,
  Sun,
  Sunset,
  Moon,
  BedDouble,
  CheckCircle2,
} from "lucide-react";
import { useTripStore } from "@/store/tripStore";
import { yuan } from "@/constants";
import { budgetLevelLabel } from "@/data/database";
import {
  replaceActivity,
  replaceHotel,
  getAlternatives,
  getHotelAlternatives,
  generateItinerary,
} from "@/engine/generator";
import { cn } from "@/lib/utils";
import type { Itinerary as ItineraryType, Activity, Hotel, DayPlan } from "@/types";

export default function ItineraryPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { getItinerary, updateItinerary, saveItinerary, resetCollaboration } =
    useTripStore();

  const [shareHint, setShareHint] = useState(false);
  const [regenerating, setRegenerating] = useState(false);

  const itinerary = useMemo(() => {
    if (!id) return null;
    return getItinerary(id) ?? null;
  }, [id, getItinerary]);

  if (!itinerary) {
    return (
      <main className="container py-20 text-center">
        <div className="mx-auto max-w-md">
          <div className="text-5xl">🗂️</div>
          <h1 className="mt-4 font-display text-2xl font-semibold text-ink">方案不存在</h1>
          <p className="mt-2 text-mist">该方案可能已被删除，或链接已失效。</p>
          <div className="mt-6 flex justify-center gap-3">
            <Link to="/history" className="btn-outline">查看历史</Link>
            <Link to="/plan" className="btn-primary">重新规划</Link>
          </div>
        </div>
      </main>
    );
  }

  const handleReplaceActivity = (
    dayIndex: number,
    slot: "morning" | "afternoon" | "evening",
    newAct: Activity
  ) => {
    const updated = replaceActivity(itinerary, dayIndex, slot, newAct);
    updateItinerary(updated);
  };

  const handleReplaceHotel = (newHotel: Hotel) => {
    const updated = replaceHotel(itinerary, newHotel);
    updateItinerary(updated);
  };

  const handleRegenerate = () => {
    setRegenerating(true);
    // 基于当前 request 重新生成（可带上方案自身的 request）
    const baseReq = itinerary.request;
    setTimeout(() => {
      const fresh = generateItinerary({ ...baseReq });
      saveItinerary(fresh);
      resetCollaboration();
      setRegenerating(false);
      navigate(`/itinerary/${fresh.id}`);
    }, 900);
  };

  const handleShare = () => {
    const url = window.location.href;
    navigator.clipboard?.writeText(url).catch(() => {});
    setShareHint(true);
    setTimeout(() => setShareHint(false), 2200);
  };

  const handlePrint = () => window.print();

  return (
    <main className="topo-texture min-h-screen pb-20">
      <div className="container py-8 md:py-12">
        {/* 顶部操作栏 */}
        <div className="no-print mb-8 flex flex-wrap items-center justify-between gap-3">
          <button
            onClick={() => navigate(-1)}
            className="inline-flex items-center gap-1.5 text-sm font-medium text-ink/60 hover:text-terracotta"
          >
            <ArrowLeft className="h-4 w-4" /> 返回
          </button>
          <div className="flex flex-wrap items-center gap-2">
            <button onClick={handleRegenerate} disabled={regenerating} className="btn-outline px-4 py-2 text-sm">
              <RefreshCw className={cn("h-4 w-4", regenerating && "animate-spin")} />
              {regenerating ? "重新生成中…" : "重新生成"}
            </button>
            <button onClick={handleShare} className="btn-outline px-4 py-2 text-sm">
              {shareHint ? <Check className="h-4 w-4 text-terracotta" /> : <Share2 className="h-4 w-4" />}
              {shareHint ? "链接已复制" : "分享链接"}
            </button>
            <button onClick={handlePrint} className="btn-primary px-4 py-2 text-sm">
              <Printer className="h-4 w-4" /> 导出 PDF
            </button>
          </div>
        </div>

        {/* 概览卡 */}
        <OverviewCard itinerary={itinerary} />

        {/* 预算分项 */}
        <BudgetSection itinerary={itinerary} />

        {/* 每日行程 */}
        <div className="mt-8">
          <h2 className="mb-5 flex items-center gap-2 font-display text-2xl font-semibold text-ink">
            <RouteIcon className="h-5 w-5 text-terracotta" />
            每日详细行程
          </h2>
          <div className="space-y-6">
            {itinerary.days.map((day, idx) => (
              <DayCard
                key={day.day}
                day={day}
                dayIndex={idx}
                itinerary={itinerary}
                onReplaceActivity={handleReplaceActivity}
                onReplaceHotel={handleReplaceHotel}
              />
            ))}
          </div>
        </div>
      </div>
    </main>
  );
}

/* ---------------- 概览卡 ---------------- */
function OverviewCard({ itinerary }: { itinerary: ItineraryType }) {
  const o = itinerary.overview;
  return (
    <div className="print-block card overflow-hidden">
      <div className="relative bg-ink p-7 text-paper md:p-9">
        <div className="topo-texture absolute inset-0 opacity-[0.13]" />
        <div className="absolute -right-16 -top-16 h-52 w-52 rounded-full bg-terracotta/20 blur-3xl" />
        <div className="absolute -bottom-20 -left-10 h-52 w-52 rounded-full bg-teal-400/15 blur-3xl" />
        <div className="relative">
          <div className="inline-flex items-center gap-1.5 rounded-full bg-terracotta px-3 py-1 text-xs font-medium">
            <Sparkles className="h-3 w-3" /> 多 Agent 协作方案
          </div>
          <h1 className="mt-4 font-display text-4xl font-semibold leading-tight md:text-5xl">
            {o.destination} {o.days} 日深度游
          </h1>
          <p className="mt-3 max-w-xl text-sm text-paper/70">
            由预算、行程、活动、餐饮四大 Agent 协作生成，预算约束、路线优化、偏好匹配三重保障。
          </p>
          <div className="mt-6 grid grid-cols-2 gap-4 sm:grid-cols-4">
            <Metric icon={Calendar} label="行程天数" value={`${o.days} 天`} />
            <Metric icon={Users} label="出行人数" value={`${o.travelers} 人`} />
            <Metric icon={Wallet} label="总预算" value={yuan(o.totalBudget)} />
            <Metric icon={Sparkles} label="人均花费" value={yuan(o.perPerson)} />
          </div>
        </div>
      </div>

      {o.preferenceSummary.length > 0 && (
        <div className="flex flex-wrap items-center gap-2 border-t border-ink/[0.06] p-5">
          <span className="text-xs font-medium text-mist">偏好总结：</span>
          {o.preferenceSummary.map((p, i) => (
            <span
              key={i}
              className="rounded-full bg-terracotta-50 px-3 py-1 text-xs font-medium text-terracotta-500"
            >
              {p}
            </span>
          ))}
          <span className="ml-auto rounded-full bg-ink/[0.04] px-3 py-1 text-xs text-ink2">
            {budgetLevelLabel[itinerary.request.budgetLevel]}
          </span>
        </div>
      )}
    </div>
  );
}

function Metric({
  icon: Icon,
  label,
  value,
}: {
  icon: React.ElementType;
  label: string;
  value: string;
}) {
  return (
    <div className="rounded-2xl bg-paper/10 p-3 backdrop-blur">
      <div className="flex items-center gap-1.5 text-xs text-paper/60">
        <Icon className="h-3.5 w-3.5" />
        {label}
      </div>
      <div className="mt-1 font-display text-xl font-semibold">{value}</div>
    </div>
  );
}

/* ---------------- 预算分项 ---------------- */
function BudgetSection({ itinerary }: { itinerary: ItineraryType }) {
  const b = itinerary.budgetBreakdown;
  const items = [
    { label: "机票交通", val: b.flight, color: "#D9633B", emoji: "✈️" },
    { label: "住宿", val: b.hotel, color: "#0F4C4C", emoji: "🏨" },
    { label: "餐饮", val: b.food, color: "#E88D61", emoji: "🍜" },
    { label: "景点门票", val: b.tickets, color: "#478C8C", emoji: "🎟️" },
    { label: "其他交通", val: b.other, color: "#B8B0A6", emoji: "🚕" },
  ];
  const total = b.total;
  return (
    <div className="print-block mt-8 card grid gap-6 p-6 md:grid-cols-[260px_1fr] md:p-7">
      {/* 环形图 */}
      <div className="flex flex-col items-center justify-center">
        <BudgetDonut items={items} total={total} />
        <div className="mt-3 text-center">
          <div className="text-xs text-mist">总预算</div>
          <div className="font-display text-2xl font-semibold text-ink">{yuan(total)}</div>
        </div>
      </div>
      {/* 分项列表 */}
      <div className="space-y-2.5">
        <h3 className="mb-1 font-display text-lg font-semibold text-ink">预算分项</h3>
        {items.map((it) => {
          const pct = total > 0 ? Math.round((it.val / total) * 100) : 0;
          return (
            <div key={it.label} className="flex items-center gap-3">
              <span className="w-7 text-center text-lg">{it.emoji}</span>
              <div className="flex-1">
                <div className="flex justify-between text-sm">
                  <span className="font-medium text-ink">{it.label}</span>
                  <span className="text-mist">
                    {yuan(it.val)} · {pct}%
                  </span>
                </div>
                <div className="mt-1 h-2 overflow-hidden rounded-full bg-ink/[0.05]">
                  <div
                    className="h-full rounded-full transition-all"
                    style={{ width: `${pct}%`, backgroundColor: it.color }}
                  />
                </div>
              </div>
            </div>
          );
        })}
        <div className="mt-3 rounded-xl bg-teal-50 px-4 py-2.5 text-xs text-teal-400">
          💡 预算优化 Agent 已按 {budgetLevelLabel[itinerary.request.budgetLevel]} 档位分配，
          如需调整可修改预算后「重新生成」
        </div>
      </div>
    </div>
  );
}

function BudgetDonut({
  items,
  total,
}: {
  items: { label: string; val: number; color: string }[];
  total: number;
}) {
  const r = 70;
  const c = 2 * Math.PI * r;
  let offset = 0;
  return (
    <svg width="180" height="180" viewBox="0 0 180 180" className="-rotate-90">
      <circle cx="90" cy="90" r={r} fill="none" stroke="#F3EEE5" strokeWidth="20" />
      {items.map((it) => {
        const frac = total > 0 ? it.val / total : 0;
        const len = frac * c;
        const seg = (
          <circle
            key={it.label}
            cx="90"
            cy="90"
            r={r}
            fill="none"
            stroke={it.color}
            strokeWidth="20"
            strokeDasharray={`${len} ${c - len}`}
            strokeDashoffset={-offset}
            strokeLinecap="butt"
          />
        );
        offset += len;
        return seg;
      })}
    </svg>
  );
}

/* ---------------- 每日行程卡 ---------------- */
function DayCard({
  day,
  dayIndex,
  itinerary,
  onReplaceActivity,
  onReplaceHotel,
}: {
  day: DayPlan;
  dayIndex: number;
  itinerary: ItineraryType;
  onReplaceActivity: (di: number, slot: "morning" | "afternoon" | "evening", act: Activity) => void;
  onReplaceHotel: (h: Hotel) => void;
}) {
  return (
    <div className="print-block card overflow-hidden">
      {/* 当日头 */}
      <div className="flex flex-wrap items-center justify-between gap-3 border-b border-ink/[0.06] bg-ink/[0.02] p-5">
        <div className="flex items-center gap-4">
          <div className="flex h-14 w-14 flex-col items-center justify-center rounded-2xl bg-terracotta text-paper">
            <span className="text-[10px] leading-none opacity-80">DAY</span>
            <span className="font-display text-2xl font-bold leading-none">{day.day}</span>
          </div>
          <div>
            <h3 className="font-display text-xl font-semibold text-ink">{day.theme}</h3>
            <div className="flex items-center gap-1.5 text-xs text-mist">
              <Calendar className="h-3 w-3" /> {day.date}
            </div>
          </div>
        </div>
        <div className="text-right">
          <div className="text-xs text-mist">当日预算</div>
          <div className="font-display text-lg font-semibold text-terracotta">
            {yuan(day.dailyBudget)}
          </div>
        </div>
      </div>

      {/* 时间段 */}
      <div className="grid gap-px bg-ink/[0.05] md:grid-cols-2">
        <TimeSlot
          icon={Sun}
          label="上午"
          color="text-terracotta"
          day={day}
          dayIndex={dayIndex}
          slot="morning"
          itinerary={itinerary}
          onReplace={onReplaceActivity}
        />
        <TimeSlot
          icon={Sunset}
          label="中午"
          color="text-terracotta-300"
          type="dining"
          day={day}
          dining={day.noon}
        />
        <TimeSlot
          icon={Sun}
          label="下午"
          color="text-teal-400"
          day={day}
          dayIndex={dayIndex}
          slot="afternoon"
          itinerary={itinerary}
          onReplace={onReplaceActivity}
        />
        <TimeSlot
          icon={Moon}
          label="晚上"
          color="text-ink"
          day={day}
          dayIndex={dayIndex}
          slot="evening"
          itinerary={itinerary}
          onReplace={onReplaceActivity}
        />
      </div>

      {/* 住宿 */}
      <div className="border-t border-ink/[0.06] p-5">
        <HotelBlock
          hotel={day.hotel}
          itinerary={itinerary}
          onReplaceHotel={onReplaceHotel}
        />
      </div>

      {/* 交通 */}
      {day.transport.length > 0 && (
        <div className="border-t border-ink/[0.06] bg-ink/[0.02] p-5">
          <div className="mb-3 flex items-center gap-2 text-sm font-medium text-ink">
            <RouteIcon className="h-4 w-4 text-terracotta" />
            当日交通指引
          </div>
          <div className="flex flex-wrap items-center gap-2 text-xs">
            {day.transport.map((t, i) => (
              <span key={i} className="inline-flex items-center gap-1.5">
                {i > 0 && <span className="text-mist">→</span>}
                <span className="rounded-lg bg-paper px-2.5 py-1 text-ink2 shadow-soft">
                  {t.from} <span className="text-mist">·</span> {t.method} {t.duration}
                  {t.cost > 0 && <span className="text-terracotta"> · {yuan(t.cost)}</span>}
                </span>
              </span>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

/* 时间段块 */
function TimeSlot({
  icon: Icon,
  label,
  color,
  day,
  dayIndex,
  slot,
  itinerary,
  onReplace,
  type = "activity",
  dining,
}: {
  icon: React.ElementType;
  label: string;
  color: string;
  day: DayPlan;
  dayIndex?: number;
  slot?: "morning" | "afternoon" | "evening";
  itinerary?: ItineraryType;
  onReplace?: (di: number, slot: "morning" | "afternoon" | "evening", act: Activity) => void;
  type?: "activity" | "dining";
  dining?: { name: string; cuisine: string; pricePerPerson: number; reason: string };
}) {
  const [editing, setEditing] = useState(false);

  if (type === "dining" && dining) {
    return (
      <div className="bg-paper p-5">
        <div className="mb-3 flex items-center gap-2">
          <Icon className={cn("h-4 w-4", color)} />
          <span className="text-xs font-semibold uppercase tracking-wider text-mist">{label}</span>
        </div>
        <div className="flex items-start gap-2.5">
          <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-xl bg-terracotta-50 text-terracotta">
            <UtensilsCrossed className="h-5 w-5" />
          </div>
          <div className="flex-1">
            <div className="font-medium text-ink">{dining.name}</div>
            <div className="text-xs text-mist">{dining.cuisine} · 人均 {yuan(dining.pricePerPerson)}</div>
            <p className="mt-1.5 text-xs leading-relaxed text-ink2">{dining.reason}</p>
          </div>
        </div>
      </div>
    );
  }

  // activity
  const act = day[slot!] as Activity;
  const alts = itinerary && dayIndex !== undefined && slot
    ? getAlternatives(itinerary, dayIndex, slot)
    : [];

  return (
    <div className="bg-paper p-5">
      <div className="mb-3 flex items-center justify-between">
        <div className="flex items-center gap-2">
          <Icon className={cn("h-4 w-4", color)} />
          <span className="text-xs font-semibold uppercase tracking-wider text-mist">{label}</span>
        </div>
        {onReplace && dayIndex !== undefined && slot && (
          <button
            onClick={() => setEditing((v) => !v)}
            className="no-print text-xs font-medium text-mist hover:text-terracotta"
          >
            {editing ? "收起" : "替换"}
          </button>
        )}
      </div>

      <div className="flex items-start gap-2.5">
        <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-xl bg-teal-50 text-teal-400">
          <MapPin className="h-5 w-5" />
        </div>
        <div className="flex-1">
          <div className="font-medium text-ink">{act.name}</div>
          <div className="mt-1 flex flex-wrap gap-x-3 gap-y-1 text-xs text-mist">
            <span className="inline-flex items-center gap-1">
              <Ticket className="h-3 w-3" />
              {act.ticketPrice > 0 ? yuan(act.ticketPrice) : "免费"}
            </span>
            <span className="inline-flex items-center gap-1">
              <Clock className="h-3 w-3" />
              {act.openHours}
            </span>
          </div>
          <p className="mt-1.5 text-xs leading-relaxed text-ink2">{act.description}</p>
          <div className="mt-1.5 text-xs text-mist">🚇 {act.transport}</div>
        </div>
      </div>

      {/* 替换面板 */}
      {editing && alts.length > 0 && (
        <div className="no-print mt-4 animate-fade-up rounded-2xl border border-terracotta/20 bg-terracotta-50/40 p-3">
          <div className="mb-2 flex items-center gap-1.5 text-xs font-medium text-terracotta-500">
            <Sparkles className="h-3 w-3" /> 活动推荐 Agent 备选
          </div>
          <div className="space-y-2">
            {alts.map((alt) => (
              <button
                key={alt.name}
                onClick={() => {
                  onReplace!(dayIndex!, slot!, alt);
                  setEditing(false);
                }}
                className="flex w-full items-start gap-2.5 rounded-xl bg-paper p-2.5 text-left transition-all hover:shadow-soft"
              >
                <MapPin className="mt-0.5 h-4 w-4 shrink-0 text-teal-400" />
                <div className="flex-1">
                  <div className="text-sm font-medium text-ink">{alt.name}</div>
                  <div className="text-xs text-mist">
                    {alt.category} · {alt.ticketPrice > 0 ? yuan(alt.ticketPrice) : "免费"} · {alt.openHours}
                  </div>
                  <p className="mt-0.5 text-xs text-ink2 line-clamp-2">{alt.description}</p>
                </div>
                <CheckCircle2 className="h-4 w-4 text-terracotta" />
              </button>
            ))}
          </div>
        </div>
      )}
      {editing && alts.length === 0 && (
        <div className="no-print mt-3 rounded-xl bg-ink/[0.03] p-3 text-xs text-mist">
          暂无更多备选景点，可尝试「重新生成」获取新方案
        </div>
      )}
    </div>
  );
}

/* 住宿块 */
function HotelBlock({
  hotel,
  itinerary,
  onReplaceHotel,
}: {
  hotel: Hotel;
  itinerary: ItineraryType;
  onReplaceHotel: (h: Hotel) => void;
}) {
  const [editing, setEditing] = useState(false);
  const alts = getHotelAlternatives(itinerary);
  return (
    <div>
      <div className="mb-3 flex items-center justify-between">
        <div className="flex items-center gap-2">
          <BedDouble className="h-4 w-4 text-terracotta" />
          <span className="text-xs font-semibold uppercase tracking-wider text-mist">住宿安排</span>
        </div>
        <button
          onClick={() => setEditing((v) => !v)}
          className="no-print text-xs font-medium text-mist hover:text-terracotta"
        >
          {editing ? "收起" : "换酒店"}
        </button>
      </div>
      <div className="flex items-start gap-2.5">
        <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-xl bg-terracotta-50 text-terracotta">
          <HotelIcon className="h-5 w-5" />
        </div>
        <div className="flex-1">
          <div className="font-medium text-ink">{hotel.name}</div>
          <div className="text-xs text-mist">
            📍 {hotel.location} · {yuan(hotel.pricePerNight)}/晚
          </div>
          <p className="mt-1.5 text-xs leading-relaxed text-ink2">{hotel.reason}</p>
        </div>
      </div>

      {editing && alts.length > 0 && (
        <div className="no-print mt-4 animate-fade-up rounded-2xl border border-terracotta/20 bg-terracotta-50/40 p-3">
          <div className="mb-2 flex items-center gap-1.5 text-xs font-medium text-terracotta-500">
            <Sparkles className="h-3 w-3" /> 预算 Agent 推荐的其他酒店
          </div>
          <div className="space-y-2">
            {alts.map((h) => (
              <button
                key={h.name}
                onClick={() => {
                  onReplaceHotel(h);
                  setEditing(false);
                }}
                className="flex w-full items-start gap-2.5 rounded-xl bg-paper p-2.5 text-left transition-all hover:shadow-soft"
              >
                <HotelIcon className="mt-0.5 h-4 w-4 shrink-0 text-terracotta" />
                <div className="flex-1">
                  <div className="text-sm font-medium text-ink">{h.name}</div>
                  <div className="text-xs text-mist">
                    📍 {h.location} · {yuan(h.pricePerNight)}/晚
                  </div>
                  <p className="mt-0.5 text-xs text-ink2">{h.reason}</p>
                </div>
                <CheckCircle2 className="h-4 w-4 text-terracotta" />
              </button>
            ))}
          </div>
        </div>
      )}
      {editing && alts.length === 0 && (
        <div className="no-print mt-3 rounded-xl bg-ink/[0.03] p-3 text-xs text-mist">
          该目的地暂无更多备选酒店
        </div>
      )}
    </div>
  );
}
