// 旅智星 - 规划页
import { useState, useRef, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import {
  MapPin,
  Calendar,
  Users,
  Wallet,
  Sparkles,
  Loader2,
  Check,
  ArrowRight,
  Plus,
  X,
  Search,
  ChevronRight,
} from "lucide-react";
import { useTripStore, AGENTS } from "@/store/tripStore";
import { destinations, budgetLevelLabel } from "@/data/database";
import { INTEREST_TAGS, SPECIAL_NEEDS, BUDGET_LEVELS, yuan } from "@/constants";
import { cn } from "@/lib/utils";
import type { InterestTag, SpecialNeed } from "@/types";

export default function Plan() {
  const navigate = useNavigate();
  const { request, collabPhase, currentItinerary, startCollaboration, saveItinerary } =
    useTripStore();

  const phase = collabPhase;

  const handleGenerate = () => {
    if (!request.destination || !request.startDate || !request.endDate) return;
    startCollaboration((it) => {
      saveItinerary(it);
    });
  };

  // 完成后自动滚动到结果
  useEffect(() => {
    if (phase === "done" && currentItinerary) {
      const el = document.getElementById("plan-result");
      el?.scrollIntoView({ behavior: "smooth", block: "start" });
    }
  }, [phase, currentItinerary]);

  return (
    <main className="topo-texture min-h-screen">
      <div className="container py-10 md:py-14">
        <PlanHeader phase={phase} />

        {phase === "idle" && <InputForm onGenerate={handleGenerate} />}

        {(phase === "working" || phase === "merging") && <CollaborationPanel />}

        {phase === "done" && currentItinerary && (
          <div id="plan-result">
            <CollaborationPanel compact />
            <ResultPreview itinerary={currentItinerary} onOpen={() => navigate(`/itinerary/${currentItinerary.id}`)} />
          </div>
        )}
      </div>
    </main>
  );
}

/* ---------------- Header ---------------- */
function PlanHeader({ phase }: { phase: string }) {
  const steps = [
    { key: "input", label: "填写需求", active: phase === "idle" },
    { key: "collab", label: "Agent 协作", active: phase === "working" || phase === "merging" },
    { key: "result", label: "查看方案", active: phase === "done" },
  ];
  return (
    <div className="mb-10">
      <div className="flex items-center gap-2 text-xs font-semibold uppercase tracking-[0.2em] text-terracotta">
        <Sparkles className="h-3.5 w-3.5" />
        开始规划
      </div>
      <h1 className="mt-2 font-display text-4xl font-semibold tracking-tight text-ink sm:text-5xl">
        告诉我们你的旅行设想
      </h1>
      <div className="mt-6 flex items-center gap-2">
        {steps.map((s, i) => (
          <div key={s.key} className="flex items-center gap-2">
            <div
              className={cn(
                "flex items-center gap-2 rounded-full px-4 py-1.5 text-sm font-medium transition-all",
                s.active ? "bg-ink text-paper" : "bg-ink/[0.04] text-mist"
              )}
            >
              <span
                className={cn(
                  "flex h-5 w-5 items-center justify-center rounded-full text-[11px]",
                  s.active ? "bg-terracotta text-paper" : "bg-mist/30 text-paper"
                )}
              >
                {i + 1}
              </span>
              {s.label}
            </div>
            {i < steps.length - 1 && <ChevronRight className="h-4 w-4 text-mist" />}
          </div>
        ))}
      </div>
    </div>
  );
}

/* ---------------- 输入表单 ---------------- */
function InputForm({ onGenerate }: { onGenerate: () => void }) {
  const { request, setField, toggleInterest, toggleSpecial, addMember, removeMember, setMember } =
    useTripStore();

  const canSubmit = request.destination && request.startDate && request.endDate;

  return (
    <div className="grid gap-8 lg:grid-cols-[1fr_360px]">
      {/* 左：表单 */}
      <div className="space-y-8">
        {/* 基础信息 */}
        <Section icon={MapPin} title="基础信息" desc="目的地、日期与人数">
          <div className="grid gap-5 md:grid-cols-2">
            <DestinationPicker />
            <div>
              <label className="label">出行人数</label>
              <div className="flex items-center gap-2">
                <button
                  type="button"
                  onClick={() => setField("travelers", Math.max(1, request.travelers - 1))}
                  className="flex h-10 w-10 items-center justify-center rounded-xl border border-ink/15 text-lg text-ink hover:border-terracotta hover:text-terracotta"
                >
                  −
                </button>
                <div className="flex h-10 flex-1 items-center justify-center rounded-xl border border-ink/15 bg-paper font-medium">
                  {request.travelers} 人
                </div>
                <button
                  type="button"
                  onClick={() => setField("travelers", Math.min(10, request.travelers + 1))}
                  className="flex h-10 w-10 items-center justify-center rounded-xl border border-ink/15 text-lg text-ink hover:border-terracotta hover:text-terracotta"
                >
                  +
                </button>
              </div>
            </div>
            <div>
              <label className="label">出发日期</label>
              <input
                type="date"
                value={request.startDate}
                onChange={(e) => setField("startDate", e.target.value)}
                className="field"
              />
            </div>
            <div>
              <label className="label">返回日期</label>
              <input
                type="date"
                value={request.endDate}
                min={request.startDate}
                onChange={(e) => setField("endDate", e.target.value)}
                className="field"
              />
            </div>
          </div>
          {request.startDate && request.endDate && (
            <div className="mt-3 inline-flex items-center gap-1.5 rounded-full bg-teal-50 px-3 py-1 text-xs font-medium text-teal-400">
              <Calendar className="h-3 w-3" />
              共 {request.days} 天 {request.days - 1} 晚
            </div>
          )}
        </Section>

        {/* 预算 */}
        <Section icon={Wallet} title="预算范围" desc="拖动选择人均总预算">
          <BudgetSlider />
        </Section>

        {/* 偏好 */}
        <Section icon={Sparkles} title="兴趣偏好" desc="选择你感兴趣的旅行元素（可多选）">
          <div className="flex flex-wrap gap-2.5">
            {INTEREST_TAGS.map(({ tag, emoji }) => (
              <button
                key={tag}
                type="button"
                onClick={() => toggleInterest(tag as InterestTag)}
                className={request.interests.includes(tag as InterestTag) ? "chip-on" : "chip-off"}
              >
                <span>{emoji}</span>
                {tag}
              </button>
            ))}
          </div>
          <div className="mt-6">
            <label className="label">特殊需求（可选）</label>
            <div className="flex flex-wrap gap-2.5">
              {SPECIAL_NEEDS.map(({ need, emoji }) => (
                <button
                  key={need}
                  type="button"
                  onClick={() => toggleSpecial(need as SpecialNeed)}
                  className={
                    request.specialNeeds.includes(need as SpecialNeed) ? "chip-on" : "chip-off"
                  }
                >
                  <span>{emoji}</span>
                  {need}
                </button>
              ))}
            </div>
          </div>
          <div className="mt-6">
            <label className="label">自定义偏好说明（可选）</label>
            <textarea
              value={request.customPreference}
              onChange={(e) => setField("customPreference", e.target.value)}
              placeholder="例如：想去小众景点，避开人潮；不喜欢早起；对海鲜过敏…"
              rows={3}
              className="field resize-none"
            />
          </div>
        </Section>

        {/* 多人偏好 */}
        <Section icon={Users} title="多人偏好协调（可选）" desc="多人出行时分别输入各自偏好，系统自动协调">
          {request.multiPreferences.length === 0 ? (
            <button type="button" onClick={addMember} className="btn-outline w-full py-3 text-sm">
              <Plus className="h-4 w-4" /> 添加同伴偏好
            </button>
          ) : (
            <div className="space-y-3">
              {request.multiPreferences.map((m, idx) => (
                <div key={idx} className="rounded-2xl border border-ink/10 bg-paper p-4">
                  <div className="flex items-center gap-2">
                    <input
                      value={m.name}
                      onChange={(e) => setMember(idx, { name: e.target.value })}
                      className="field h-9 flex-1 py-1 text-sm"
                      placeholder="同伴称呼"
                    />
                    <button
                      type="button"
                      onClick={() => removeMember(idx)}
                      className="flex h-9 w-9 items-center justify-center rounded-xl text-mist hover:bg-terracotta-50 hover:text-terracotta"
                    >
                      <X className="h-4 w-4" />
                    </button>
                  </div>
                  <div className="mt-3 flex flex-wrap gap-2">
                    {INTEREST_TAGS.slice(0, 6).map(({ tag, emoji }) => {
                      const on = m.preferences.includes(tag);
                      return (
                        <button
                          key={tag}
                          type="button"
                          onClick={() =>
                            setMember(idx, {
                              preferences: on
                                ? m.preferences.filter((t) => t !== tag)
                                : [...m.preferences, tag],
                            })
                          }
                          className={cn(
                            "rounded-full border px-3 py-1 text-xs font-medium transition-all",
                            on
                              ? "border-teal-400 bg-teal-50 text-teal-500"
                              : "border-ink/15 text-ink/50 hover:border-teal-300"
                          )}
                        >
                          {emoji} {tag}
                        </button>
                      );
                    })}
                  </div>
                </div>
              ))}
              <button type="button" onClick={addMember} className="btn-ghost w-full text-sm">
                <Plus className="h-4 w-4" /> 再添加一位同伴
              </button>
            </div>
          )}
        </Section>
      </div>

      {/* 右：摘要 + 生成按钮 */}
      <div className="lg:sticky lg:top-24 lg:h-fit">
        <div className="card overflow-hidden">
          <div className="bg-ink p-5 text-paper">
            <div className="text-xs uppercase tracking-wider text-paper/60">需求摘要</div>
            <div className="mt-2 font-display text-2xl font-semibold">
              {request.destination || "待选择目的地"}
            </div>
          </div>
          <div className="space-y-3 p-5">
            <SummaryRow icon={Calendar} label="行程天数" value={request.days + " 天"} />
            <SummaryRow icon={Users} label="出行人数" value={request.travelers + " 人"} />
            <SummaryRow
              icon={Wallet}
              label="人均预算"
              value={yuan(request.budgetPerPerson)}
            />
            <SummaryRow
              icon={Sparkles}
              label="预算档位"
              value={budgetLevelLabel[request.budgetLevel]}
            />
            {request.interests.length > 0 && (
              <div className="border-t border-ink/[0.06] pt-3">
                <div className="text-xs text-mist">兴趣偏好</div>
                <div className="mt-1.5 flex flex-wrap gap-1.5">
                  {request.interests.map((t) => (
                    <span
                      key={t}
                      className="rounded-full bg-terracotta-50 px-2.5 py-0.5 text-xs font-medium text-terracotta-500"
                    >
                      {t}
                    </span>
                  ))}
                </div>
              </div>
            )}
          </div>
          <div className="border-t border-ink/[0.06] p-5">
            <button
              type="button"
              onClick={onGenerate}
              disabled={!canSubmit}
              className="btn-primary w-full py-4 text-base"
            >
              <Sparkles className="h-4 w-4" />
              启动 Agent 协作
            </button>
            {!canSubmit && (
              <p className="mt-2 text-center text-xs text-mist">
                请先填写目的地和出行日期
              </p>
            )}
            <p className="mt-3 text-center text-xs text-mist">
              首次生成免费 · 预计耗时约 15 秒
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}

function Section({
  icon: Icon,
  title,
  desc,
  children,
}: {
  icon: React.ElementType;
  title: string;
  desc?: string;
  children: React.ReactNode;
}) {
  return (
    <div className="card p-6 md:p-7">
      <div className="mb-5 flex items-center gap-3">
        <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-terracotta-50 text-terracotta">
          <Icon className="h-5 w-5" />
        </div>
        <div>
          <h2 className="font-display text-xl font-semibold text-ink">{title}</h2>
          {desc && <p className="text-xs text-mist">{desc}</p>}
        </div>
      </div>
      {children}
    </div>
  );
}

function SummaryRow({
  icon: Icon,
  label,
  value,
}: {
  icon: React.ElementType;
  label: string;
  value: string;
}) {
  return (
    <div className="flex items-center justify-between text-sm">
      <span className="inline-flex items-center gap-2 text-mist">
        <Icon className="h-4 w-4" />
        {label}
      </span>
      <span className="font-medium text-ink">{value}</span>
    </div>
  );
}

/* 目的地搜索 */
function DestinationPicker() {
  const { request, setField } = useTripStore();
  const [open, setOpen] = useState(false);
  const [query, setQuery] = useState("");
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const onClick = (e: MouseEvent) => {
      if (ref.current && !ref.current.contains(e.target as Node)) setOpen(false);
    };
    document.addEventListener("mousedown", onClick);
    return () => document.removeEventListener("mousedown", onClick);
  }, []);

  const filtered = destinations.filter(
    (d) =>
      d.name.includes(query) ||
      d.nameEn.toLowerCase().includes(query.toLowerCase()) ||
      d.country.includes(query)
  );

  return (
    <div>
      <label className="label">目的地</label>
      <div ref={ref} className="relative">
        <div className="relative">
          <Search className="pointer-events-none absolute left-3.5 top-1/2 h-4 w-4 -translate-y-1/2 text-mist" />
          <input
            value={query || request.destination}
            onChange={(e) => {
              setQuery(e.target.value);
              setOpen(true);
            }}
            onFocus={() => setOpen(true)}
            placeholder="搜索城市，如 东京 / 巴厘岛 / 成都"
            className="field pl-10"
          />
        </div>
        {open && (
          <div className="absolute z-30 mt-2 max-h-72 w-full overflow-auto rounded-2xl border border-ink/10 bg-paper p-1.5 shadow-lift">
            {filtered.map((d) => (
              <button
                key={d.name}
                type="button"
                onClick={() => {
                  setField("destination", d.name);
                  setQuery("");
                  setOpen(false);
                }}
                className="flex w-full items-center gap-3 rounded-xl px-3 py-2.5 text-left transition-colors hover:bg-terracotta-50"
              >
                <span className="text-xl">{d.emoji}</span>
                <div className="flex-1">
                  <div className="text-sm font-medium text-ink">
                    {d.name} <span className="text-mist">· {d.nameEn}</span>
                  </div>
                  <div className="text-xs text-mist">{d.country} · {d.blurb}</div>
                </div>
              </button>
            ))}
            {filtered.length === 0 && (
              <div className="px-3 py-4 text-center text-sm text-mist">
                暂无匹配，将使用通用方案
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

/* 预算滑块 */
function BudgetSlider() {
  const { request, setField } = useTripStore();
  const level = BUDGET_LEVELS.find((l) => l.level === request.budgetLevel);
  return (
    <div>
      <div className="flex items-end justify-between">
        <div>
          <span className="font-display text-4xl font-semibold text-ink">
            {yuan(request.budgetPerPerson)}
          </span>
          <span className="ml-1 text-sm text-mist">/ 人</span>
        </div>
        <span
          className={cn(
            "rounded-full px-3 py-1 text-xs font-medium",
            level?.level === "economy" && "bg-teal-50 text-teal-400",
            level?.level === "comfort" && "bg-terracotta-50 text-terracotta-500",
            level?.level === "quality" && "bg-terracotta-100 text-terracotta-600",
            level?.level === "luxury" && "bg-ink text-paper"
          )}
        >
          {level?.label}
        </span>
      </div>
      <input
        type="range"
        min={1500}
        max={30000}
        step={500}
        value={request.budgetPerPerson}
        onChange={(e) => setField("budgetPerPerson", Number(e.target.value))}
        className="mt-4 w-full accent-terracotta"
      />
      <div className="mt-2 flex justify-between text-xs text-mist">
        {BUDGET_LEVELS.map((l) => (
          <span key={l.level} className="text-center">
            {l.label}
          </span>
        ))}
      </div>
      <div className="mt-3 rounded-xl bg-ink/[0.03] px-4 py-2.5 text-xs text-ink2">
        {request.travelers} 人出行 · 总预算约{" "}
        <span className="font-semibold text-terracotta">
          {yuan(request.budgetPerPerson * request.travelers)}
        </span>
      </div>
    </div>
  );
}

/* ---------------- Agent 协作面板 ---------------- */
function CollaborationPanel({ compact = false }: { compact?: boolean }) {
  const { agents, collabPhase, request } = useTripStore();
  return (
    <div className={cn("space-y-6", compact && "opacity-90")}>
      {/* 总览条 */}
      <div className="card flex flex-wrap items-center justify-between gap-4 p-5">
        <div className="flex items-center gap-3">
          <div className="relative flex h-12 w-12 items-center justify-center rounded-2xl bg-ink text-2xl">
            {collabPhase === "done" ? "✅" : collabPhase === "merging" ? "🔗" : "⚙️"}
            {collabPhase !== "done" && (
              <span className="absolute inset-0 rounded-2xl ring-2 ring-terracotta/40 animate-pulse-ring" />
            )}
          </div>
          <div>
            <div className="font-display text-lg font-semibold text-ink">
              {collabPhase === "done"
                ? "方案生成完成"
                : collabPhase === "merging"
                ? "共享上下文协同优化中…"
                : "四大 Agent 并行协作中…"}
            </div>
            <div className="text-xs text-mist">
              目的地 {request.destination} · {request.days} 天 · {request.travelers} 人
            </div>
          </div>
        </div>
        <div className="flex items-center gap-2">
          {agents.map((a) => (
            <span
              key={a.id}
              className={cn(
                "flex h-2.5 w-2.5 rounded-full transition-colors",
                a.status === "done" && "bg-terracotta",
                a.status === "working" && "bg-terracotta-200 animate-pulse",
                a.status === "idle" && "bg-mist/40"
              )}
            />
          ))}
        </div>
      </div>

      {/* 四 Agent 卡 */}
      <div className="grid gap-4 md:grid-cols-2">
        {agents.map((a, i) => {
          const meta = AGENTS[i];
          return (
            <div
              key={a.id}
              className={cn(
                "rounded-3xl border p-5 transition-all",
                a.status === "done"
                  ? "border-terracotta/20 bg-terracotta-50/40"
                  : a.status === "working"
                  ? "border-terracotta/30 bg-paper shadow-glow"
                  : "border-ink/[0.06] bg-paper"
              )}
            >
              <div className="flex items-center gap-3">
                <div
                  className={cn(
                    "flex h-11 w-11 items-center justify-center rounded-2xl text-xl transition-all",
                    a.status === "done" ? "bg-terracotta" : "bg-ink",
                    a.status === "working" && "ring-4 ring-terracotta/20"
                  )}
                >
                  {a.status === "done" ? <Check className="h-5 w-5 text-paper" /> : meta.emoji}
                </div>
                <div className="flex-1">
                  <div className="flex items-center gap-2">
                    <span className="font-display text-base font-semibold text-ink">
                      {a.name}
                    </span>
                    <StatusTag status={a.status} />
                  </div>
                  <p className="text-xs text-mist">{a.desc}</p>
                </div>
              </div>

              {/* 进度条 */}
              <div className="mt-4">
                <div className="flex justify-between text-xs text-mist">
                  <span>{a.status === "done" ? "已完成" : a.status === "working" ? "工作中" : "等待中"}</span>
                  <span>{a.progress}%</span>
                </div>
                <div className="relative mt-1.5 h-2 overflow-hidden rounded-full bg-ink/[0.06]">
                  <div
                    className={cn(
                      "h-full rounded-full transition-all duration-500",
                      a.status === "done" ? "bg-terracotta" : "bg-terracotta-200"
                    )}
                    style={{ width: `${a.progress}%` }}
                  >
                    {a.status === "working" && (
                      <div className="absolute inset-0 progress-shimmer" />
                    )}
                  </div>
                </div>
              </div>

              {/* 日志流 */}
              {a.logs.length > 0 && (
                <div className="mt-3 max-h-28 space-y-1 overflow-auto rounded-xl bg-ink/[0.03] p-3">
                  {a.logs.map((log, li) => (
                    <div
                      key={li}
                      className="flex items-start gap-1.5 text-xs text-ink2 animate-fade-in"
                    >
                      <span className="text-terracotta">›</span>
                      <span>{log}</span>
                    </div>
                  ))}
                  {a.status === "working" && (
                    <div className="flex items-center gap-1.5 text-xs text-mist">
                      <Loader2 className="h-3 w-3 animate-spin" />
                      <span>处理中…</span>
                    </div>
                  )}
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* 共享上下文汇聚 */}
      {(collabPhase === "merging" || collabPhase === "done") && (
        <div className="animate-fade-up card overflow-hidden">
          <div className="bg-gradient-to-r from-ink to-ink2 p-5 text-paper">
            <div className="flex items-center gap-2">
              <Sparkles className="h-4 w-4 text-terracotta-200" />
              <span className="text-sm font-medium">共享上下文协同优化</span>
            </div>
            <p className="mt-1.5 text-xs text-paper/70">
              预算约束方案，方案满足偏好，路线减少折返——四大 Agent 的产出在此交汇融合
            </p>
            <div className="mt-3 flex flex-wrap gap-1.5">
              {["预算校验 ✓", "路线优化 ✓", "偏好匹配 ✓", "餐饮适配 ✓"].map((t) => (
                <span
                  key={t}
                  className="rounded-full bg-paper/10 px-2.5 py-0.5 text-xs text-paper/90"
                >
                  {t}
                </span>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function StatusTag({ status }: { status: string }) {
  return (
    <span
      className={cn(
        "rounded-full px-2 py-0.5 text-[10px] font-medium",
        status === "done" && "bg-terracotta text-paper",
        status === "working" && "bg-terracotta-100 text-terracotta-600",
        status === "idle" && "bg-mist/20 text-mist"
      )}
    >
      {status === "done" ? "已完成" : status === "working" ? "工作中" : "等待中"}
    </span>
  );
}

/* ---------------- 结果预览 ---------------- */
function ResultPreview({
  itinerary,
  onOpen,
}: {
  itinerary: import("@/types").Itinerary;
  onOpen: () => void;
}) {
  return (
    <div className="mt-8 animate-fade-up">
      <div className="card overflow-hidden">
        <div className="relative bg-ink p-6 text-paper md:p-8">
          <div className="topo-texture absolute inset-0 opacity-[0.12]" />
          <div className="absolute -right-12 -top-12 h-40 w-40 rounded-full bg-terracotta/20 blur-3xl" />
          <div className="relative">
            <div className="inline-flex items-center gap-1.5 rounded-full bg-terracotta px-3 py-1 text-xs font-medium">
              <Check className="h-3 w-3" /> 方案已生成
            </div>
            <h2 className="mt-4 font-display text-4xl font-semibold">
              {itinerary.overview.destination} {itinerary.overview.days} 日深度游
            </h2>
            <div className="mt-4 flex flex-wrap gap-6 text-sm">
              <Metric label="总预算" value={yuan(itinerary.overview.totalBudget)} />
              <Metric label="人均" value={yuan(itinerary.overview.perPerson)} />
              <Metric label="出行人数" value={itinerary.overview.travelers + " 人"} />
            </div>
          </div>
        </div>

        {/* 预算分项 */}
        <div className="grid gap-3 p-6 sm:grid-cols-2 md:grid-cols-5">
          {[
            { label: "机票交通", val: itinerary.budgetBreakdown.flight, emoji: "✈️" },
            { label: "住宿", val: itinerary.budgetBreakdown.hotel, emoji: "🏨" },
            { label: "餐饮", val: itinerary.budgetBreakdown.food, emoji: "🍜" },
            { label: "门票", val: itinerary.budgetBreakdown.tickets, emoji: "🎟️" },
            { label: "其他", val: itinerary.budgetBreakdown.other, emoji: "🚕" },
          ].map((b) => (
            <div key={b.label} className="rounded-2xl bg-ink/[0.03] p-3 text-center">
              <div className="text-xl">{b.emoji}</div>
              <div className="mt-1 text-xs text-mist">{b.label}</div>
              <div className="font-display text-lg font-semibold text-ink">{yuan(b.val)}</div>
            </div>
          ))}
        </div>

        {/* 每日概览 */}
        <div className="border-t border-ink/[0.06] p-6">
          <h3 className="mb-4 font-display text-lg font-semibold text-ink">每日行程概览</h3>
          <div className="space-y-3">
            {itinerary.days.map((d) => (
              <div
                key={d.day}
                className="flex items-center gap-4 rounded-2xl border border-ink/[0.06] p-3"
              >
                <div className="flex h-12 w-12 shrink-0 flex-col items-center justify-center rounded-xl bg-terracotta text-paper">
                  <span className="text-[10px] leading-none">DAY</span>
                  <span className="font-display text-lg font-bold leading-none">{d.day}</span>
                </div>
                <div className="flex-1">
                  <div className="text-sm font-medium text-ink">{d.theme}</div>
                  <div className="text-xs text-mist">
                    {d.morning.name} → {d.afternoon.name}
                    {d.evening.kind === "activity" ? ` → ${d.evening.name}` : ""}
                  </div>
                </div>
                <div className="text-right">
                  <div className="text-xs text-mist">当日预算</div>
                  <div className="text-sm font-semibold text-terracotta">{yuan(d.dailyBudget)}</div>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div className="flex flex-col gap-3 border-t border-ink/[0.06] p-6 sm:flex-row">
          <button onClick={onOpen} className="btn-primary flex-1 py-3.5">
            查看完整方案 <ArrowRight className="h-4 w-4" />
          </button>
        </div>
      </div>
    </div>
  );
}

function Metric({ label, value }: { label: string; value: string }) {
  return (
    <div>
      <div className="text-xs text-paper/50">{label}</div>
      <div className="font-display text-xl font-semibold">{value}</div>
    </div>
  );
}
