// 旅智星 - 行程方案生成器
import type {
  TripRequest,
  Itinerary,
  DayPlan,
  Activity,
  Dining,
  Hotel,
  BudgetBreakdown,
  ItineraryOverview,
} from "@/types";
import {
  getActivities,
  getDining,
  getHotels,
  budgetMultiplier,
  dayThemes,
  makeTransport,
} from "@/data/database";

// 计算两个日期之间的天数（含起止）
export function calcDays(start: string, end: string): number {
  if (!start || !end) return 1;
  const s = new Date(start).getTime();
  const e = new Date(end).getTime();
  if (isNaN(s) || isNaN(e) || e < s) return 1;
  return Math.round((e - s) / 86400000) + 1;
}

// 根据人均预算判定档位
export function levelFromBudget(per: number): TripRequest["budgetLevel"] {
  if (per < 3000) return "economy";
  if (per < 6000) return "comfort";
  if (per < 12000) return "quality";
  return "luxury";
}

function uid(): string {
  return "trip-" + Date.now().toString(36) + Math.random().toString(36).slice(2, 7);
}

function pick<T>(arr: T[], idx: number): T {
  return arr[idx % arr.length];
}

function addDays(dateStr: string, n: number): string {
  const d = new Date(dateStr);
  d.setDate(d.getDate() + n);
  return d.toISOString().slice(0, 10);
}

// 生成完整方案
export function generateItinerary(req: TripRequest): Itinerary {
  const days = Math.max(1, req.days);
  const mult = budgetMultiplier[req.budgetLevel] ?? 1;
  const travelers = Math.max(1, req.travelers);

  const activities = getActivities(req.destination, req.interests);
  const dining = getDining(req.destination);
  const hotels = getHotels(req.destination);

  // 选择酒店：根据档位选择合适价位的酒店
  const hotelPool = [...hotels].sort((a, b) => a.pricePerNight - b.pricePerNight);
  const hotelIdx =
    req.budgetLevel === "economy"
      ? 0
      : req.budgetLevel === "comfort"
      ? Math.min(1, hotelPool.length - 1)
      : req.budgetLevel === "quality"
      ? Math.min(hotelPool.length - 1, Math.floor(hotelPool.length / 2))
      : hotelPool.length - 1;
  const baseHotel = hotelPool[hotelIdx] ?? hotelPool[0];
  // 价格按档位系数缩放
  const scaleHotel: Hotel = {
    ...baseHotel,
    pricePerNight: Math.round((baseHotel.pricePerNight * mult) / 10) * 10,
  };

  // 机票估算（往返，按国内/海外粗估）
  const isOverseas = !["香港", "台北", "成都", "丽江", "厦门", "大理"].includes(req.destination);
  const baseFlight = isOverseas ? 2800 : 1200;
  const flightPerPerson = Math.round((baseFlight * mult) / 10) * 10;

  const dayPlans: DayPlan[] = [];
  let ticketsSum = 0;
  let foodSum = 0;
  let transportSum = 0;

  for (let i = 0; i < days; i++) {
    const dateStr = addDays(req.startDate, i);
    const theme = pick(dayThemes, i);

    // 上午、下午各一个景点（避免重复）
    const morningAct = scaleAct(activities[i % activities.length], mult);
    const afternoonAct = scaleAct(
      activities[(i + 2) % activities.length],
      mult
    );

    // 午餐、晚餐
    const noonDine = scaleDine(pick(dining, i), mult);
    // 晚上：偶数天用景点，奇数天用晚餐推荐
    let evening: Activity | Dining;
    if (i % 2 === 0) {
      const evAct = scaleAct(activities[(i + 4) % activities.length], mult);
      evening = evAct;
      ticketsSum += evAct.ticketPrice * travelers;
    } else {
      const evDine = scaleDine(pick(dining, i + 1), mult);
      evening = evDine;
      foodSum += evDine.pricePerPerson * travelers;
    }

    ticketsSum += morningAct.ticketPrice * travelers + afternoonAct.ticketPrice * travelers;
    foodSum += noonDine.pricePerPerson * travelers;

    // 交通段
    const transport = [
      makeTransport(req.destination + "酒店", morningAct.name, i),
      makeTransport(morningAct.name, noonDine.name, i + 1),
      makeTransport(noonDine.name, afternoonAct.name, i + 2),
      makeTransport(afternoonAct.name, scaleHotel.name, i + 3),
    ];
    transportSum += transport.reduce((s, t) => s + t.cost, 0) * travelers;

    // 当日预算（人均）
    const dailyPer =
      flightPerPerson / days +
      scaleHotel.pricePerNight +
      noonDine.pricePerPerson +
      (evening.kind === "dining" ? evening.pricePerPerson : 0) +
      morningAct.ticketPrice +
      afternoonAct.ticketPrice +
      (evening.kind === "activity" ? evening.ticketPrice : 0) +
      transport.reduce((s, t) => s + t.cost, 0);

    dayPlans.push({
      day: i + 1,
      date: dateStr,
      theme,
      dailyBudget: Math.round(dailyPer * travelers),
      morning: morningAct,
      noon: noonDine,
      afternoon: afternoonAct,
      evening,
      hotel: scaleHotel,
      transport,
    });
  }

  const flightTotal = flightPerPerson * travelers;
  const hotelTotal = scaleHotel.pricePerNight * days * travelers;
  const foodTotal = foodSum;
  const ticketsTotal = ticketsSum;
  const otherTotal = Math.round(transportSum + flightTotal * 0.1);
  const total = flightTotal + hotelTotal + foodTotal + ticketsTotal + otherTotal;

  const breakdown: BudgetBreakdown = {
    flight: flightTotal,
    hotel: hotelTotal,
    food: foodTotal,
    tickets: ticketsTotal,
    other: otherTotal,
    total,
  };

  const preferenceSummary = [
    ...req.interests,
    ...req.specialNeeds,
    ...(req.customPreference ? [req.customPreference] : []),
  ];

  const overview: ItineraryOverview = {
    destination: req.destination,
    days,
    totalBudget: total,
    perPerson: Math.round(total / travelers),
    travelers,
    preferenceSummary,
  };

  return {
    id: uid(),
    request: req,
    createdAt: Date.now(),
    overview,
    budgetBreakdown: breakdown,
    days: dayPlans,
  };
}

function scaleAct(a: Activity, mult: number): Activity {
  return {
    ...a,
    ticketPrice: Math.round(a.ticketPrice * mult),
  };
}
function scaleDine(d: Dining, mult: number): Dining {
  return {
    ...d,
    pricePerPerson: Math.round((d.pricePerPerson * mult) / 5) * 5,
  };
}

// 增量替换：用备选景点/酒店替换某天某时段
export function replaceActivity(
  itinerary: Itinerary,
  dayIndex: number,
  slot: "morning" | "afternoon" | "evening",
  newActivity: Activity
): Itinerary {
  const days = itinerary.days.map((d, i) => {
    if (i !== dayIndex) return d;
    return { ...d, [slot]: newActivity };
  });
  return { ...itinerary, days };
}

export function replaceHotel(itinerary: Itinerary, newHotel: Hotel): Itinerary {
  const days = itinerary.days.map((d) => ({ ...d, hotel: newHotel }));
  return { ...itinerary, days };
}

// 获取某天某时段的可替换备选
export function getAlternatives(
  itinerary: Itinerary,
  dayIndex: number,
  slot: "morning" | "afternoon" | "evening"
): Activity[] {
  const used = new Set<string>();
  itinerary.days.forEach((d, i) => {
    used.add(d.morning.name);
    used.add(d.afternoon.name);
    if (i !== dayIndex && d.evening.kind === "activity") used.add(d.evening.name);
  });
  const all = getActivities(itinerary.request.destination, itinerary.request.interests);
  const current = itinerary.days[dayIndex][slot];
  return all.filter((a) => !used.has(a.name) && a.name !== current.name).slice(0, 4);
}

export function getHotelAlternatives(itinerary: Itinerary): Hotel[] {
  const all = getHotels(itinerary.request.destination);
  const current = itinerary.days[0].hotel.name;
  return all.filter((h) => h.name !== current);
}
