// 旅智星 - 顶部导航
import { Link, useLocation } from "react-router-dom";
import { Compass, History, MapPinned, Home as HomeIcon } from "lucide-react";
import { cn } from "@/lib/utils";

export function Navbar() {
  const loc = useLocation();
  const links = [
    { to: "/", label: "首页", icon: HomeIcon },
    { to: "/plan", label: "开始规划", icon: MapPinned },
    { to: "/history", label: "历史方案", icon: History },
  ];
  return (
    <header className="no-print sticky top-0 z-50 border-b border-ink/[0.06] bg-paper/80 backdrop-blur-xl">
      <div className="container flex h-16 items-center justify-between">
        <Link to="/" className="flex items-center gap-2.5 group">
          <span className="relative flex h-9 w-9 items-center justify-center rounded-xl bg-ink text-paper transition-transform group-hover:rotate-12">
            <Compass className="h-5 w-5" />
            <span className="absolute -right-0.5 -top-0.5 h-2.5 w-2.5 rounded-full bg-terracotta ring-2 ring-paper" />
          </span>
          <div className="leading-none">
            <div className="font-display text-xl font-semibold tracking-tight text-ink">
              旅智星
            </div>
            <div className="text-[10px] uppercase tracking-[0.18em] text-mist">
              Atlas AI Planner
            </div>
          </div>
        </Link>

        <nav className="flex items-center gap-1">
          {links.map((l) => {
            const active = loc.pathname === l.to;
            const Icon = l.icon;
            return (
              <Link
                key={l.to}
                to={l.to}
                className={cn(
                  "flex items-center gap-1.5 rounded-full px-4 py-2 text-sm font-medium transition-all",
                  active
                    ? "bg-ink text-paper"
                    : "text-ink/60 hover:bg-ink/[0.05] hover:text-ink"
                )}
              >
                <Icon className="h-4 w-4" />
                <span className="hidden sm:inline">{l.label}</span>
              </Link>
            );
          })}
          <Link to="/plan" className="btn-primary ml-2 px-5 py-2 text-sm">
            立即规划
          </Link>
        </nav>
      </div>
    </header>
  );
}
