// 旅智星 - Zustand 状态管理
import { create } from "zustand";
import { persist } from "zustand/middleware";
import type {
  TripRequest,
  Itinerary,
  AgentId,
  AgentState,
  InterestTag,
  SpecialNeed,
  MemberPreference,
} from "@/types";
import { levelFromBudget } from "@/engine/generator";
import { generateItinerary } from "@/engine/generator";

// 四大 Agent 元信息
