// 旅智星 - 历史页
import { Link, useNavigate } from "react-router-dom";
import {
  Calendar,
  Users,
  Wallet,
  Trash2,
  Eye,
  Copy,
  Sparkles,
  ArrowRight,
  Plane,
} from "lucide-react";
import { useTripStore } from "@/store/tripStore";
import { yuan } from "@/constants";
import { budgetLevelLabel, findDestination } from "@/data/database";
import { generateItinerary } from "@/engine/generator";
import { useState } from "react";

export default function History() {
  const navigate = useNavigate();
  const { history, deleteItinerary, saveItinerary } = useTripStore();
  const [confirmId, setConfirmId] = useState<string | null>(null);

  const handleReuse = (id: string) => {
    const it = history.find((h) => h.id === id);
    if (!it) return;
    const fresh = generateItinerary({ ...it.request });
    saveItinerary(fresh);
    navigate(`/itinerary/${fresh.id}`);
  };

  return (
    <main className="topo-texture min-h-screen pb-20">
      <div className="container py-10 md:py-14">
        {/* 头 */}
        <div className="mb-10">
          <div className="flex items-center gap-2 text-xs font-semibold uppercase tracking-[0.2em] text-terracotta">
            <Calendar className="h-3.5 w-3.5" />
            历史方案
          </div>
          <h1 className="mt-2 font-display text-4xl font-semibold tracking-tight text-ink sm:text-5xl">
            你的旅行方案库
          </h1>
          <p className="mt-3 text-ink2">
            所有生成的方案自动保存于此，可随时回看、复用或删除。
          </p>
        </div>

        {history.length === 0 ? (
          <EmptyState />
        ) : (
          <>
            <div className="mb-6 flex items-center justify-between">
              <span className="text-sm text-mist">共 {history.length} 份方案</span>
              <Link to="/plan" className="btn-primary px-5 py-2 text-sm">
                <Sparkles className="h-4 w-4" /> 新建方案
              </Link>
            </div>
            <div className="grid gap-5 sm:grid-cols-2 lg:grid-cols-3">
              {history.map((it) => {
                const dest = findDestination(it.overview.destination);
                return (
                  <div
                    key={it.id}
                    className="group card overflow-hidden transition-all hover:-translate-y-1 hover:shadow-lift"
                  >
                    {/* 头图区 */}
                    <div className="relative flex h-32 items-center justify-center overflow-hidden bg-ink">
                      <div className="topo-texture absolute inset-0 opacity-20" />
                      <div className="absolute -right-8 -top-8 h-28 w-28 rounded-full bg-terracotta/20 blur-2xl" />
                      <span className="relative text-5xl">{dest?.emoji ?? "🗺️"}</span>
                      <span className="absolute right-3 top-3 rounded-full bg-paper/90 px-2.5 py-0.5 text-[10px] font-medium text-terracotta-500">
                        {budgetLevelLabel[it.request.budgetLevel]}
                      </span>
                    </div>

                    {/* 内容 */}
                    <div className="p-5">
                      <h3 className="font-display text-xl font-semibold text-ink">
                        {it.overview.destination} {it.overview.days} 日游
                      </h3>
                      <div className="mt-1 text-xs text-mist">
                        {new Date(it.createdAt).toLocaleString("zh-CN", {
                          month: "2-digit",
                          day: "2-digit",
                          hour: "2-digit",
                          minute: "2-digit",
                        })}{" "}
                        生成
                      </div>

                      <div className="mt-4 grid grid-cols-3 gap-2 text-center">
                        <Mini icon={Calendar} value={`${it.overview.days}天`} />
                        <Mini icon={Users} value={`${it.overview.travelers}人`} />
                        <Mini icon={Wallet} value={yuan(it.overview.totalBudget)} />
                      </div>

                      {it.overview.preferenceSummary.length > 0 && (
                        <div className="mt-3 flex flex-wrap gap-1">
                          {it.overview.preferenceSummary.slice(0, 3).map((p, i) => (
                            <span
                              key={i}
                              className="rounded-full bg-terracotta-50 px-2 py-0.5 text-[10px] font-medium text-terracotta-500"
                            >
                              {p}
                            </span>
                          ))}
                          {it.overview.preferenceSummary.length > 3 && (
                            <span className="rounded-full bg-ink/[0.04] px-2 py-0.5 text-[10px] text-mist">
                              +{it.overview.preferenceSummary.length - 3}
                            </span>
                          )}
                        </div>
                      )}

                      {/* 操作 */}
                      <div className="mt-4 flex items-center gap-2 border-t border-ink/[0.06] pt-4">
                        <button
                          onClick={() => navigate(`/itinerary/${it.id}`)}
                          className="btn-primary flex-1 py-2 text-xs"
                        >
                          <Eye className="h-3.5 w-3.5" /> 查看
                        </button>
                        <button
                          onClick={() => handleReuse(it.id)}
                          title="基于此方案重新生成"
                          className="flex h-9 w-9 items-center justify-center rounded-full border border-ink/15 text-ink/60 transition-all hover:border-terracotta hover:text-terracotta"
                        >
                          <Copy className="h-4 w-4" />
                        </button>
                        {confirmId === it.id ? (
                          <div className="flex items-center gap-1">
                            <button
                              onClick={() => {
                                deleteItinerary(it.id);
                                setConfirmId(null);
                              }}
                              className="flex h-9 items-center rounded-full bg-terracotta px-3 text-xs font-medium text-paper"
                            >
                              确认删除
                            </button>
                            <button
                              onClick={() => setConfirmId(null)}
                              className="flex h-9 w-9 items-center justify-center rounded-full border border-ink/15 text-mist"
                            >
                              ✕
                            </button>
                          </div>
                        ) : (
                          <button
                            onClick={() => setConfirmId(it.id)}
                            title="删除"
                            className="flex h-9 w-9 items-center justify-center rounded-full border border-ink/15 text-ink/60 transition-all hover:border-terracotta hover:text-terracotta"
                          >
                            <Trash2 className="h-4 w-4" />
                          </button>
                        )}
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </>
        )}
      </div>
    </main>
  );
}

function Mini({ icon: Icon, value }: { icon: React.ElementType; value: string }) {
  return (
    <div className="rounded-xl bg-ink/[0.03] py-2">
      <Icon className="mx-auto h-3.5 w-3.5 text-terracotta" />
      <div className="mt-0.5 text-xs font-medium text-ink">{value}</div>
    </div>
  );
}

function EmptyState() {
  return (
    <div className="card mx-auto max-w-lg p-10 text-center">
      <div className="mx-auto flex h-20 w-20 items-center justify-center rounded-full bg-terracotta-50 text-4xl">
        🗺️
      </div>
      <h2 className="mt-5 font-display text-2xl font-semibold text-ink">
        还没有旅行方案
      </h2>
      <p className="mt-2 text-sm text-mist">
        去规划页输入目的地与预算，让四大 Agent 为你生成第一份方案吧。
      </p>
      <Link to="/plan" className="btn-primary mt-6 px-7 py-3">
        <Sparkles className="h-4 w-4" /> 开始规划 <ArrowRight className="h-4 w-4" />
      </Link>
      <div className="mt-8 flex items-center justify-center gap-2 text-xs text-mist">
        <Plane className="h-3.5 w-3.5" /> 方案将自动保存到此
      </div>
    </div>
  );
}
