// 工厂函数
function a(
  name: string,
  description: string,
  ticketPrice: number,
  openHours: string,
  transport: string,
  category: InterestTag
): Activity {
  return { kind: "activity", name, description, ticketPrice, openHours, transport, category };
}
function d(name: string, cuisine: string, pricePerPerson: number, reason: string): Dining {
  return { kind: "dining", name, cuisine, pricePerPerson, reason };
}
function h(name: string, location: string, pricePerNight: number, reason: string): Hotel {
  return { name, location, pricePerNight, reason };
}

// 查询：按城市取景点，按偏好优先排序
export function getActivities(city: string, interests: InterestTag[]): Activity[] {
  const list = cityActivities[city] ?? genericActivities;
  // 命中偏好的排前面
  return [...list].sort((x, y) => {
    const sx = interests.includes(x.category) ? -1 : 0;
    const sy = interests.includes(y.category) ? -1 : 0;
    return sx - sy;
  });
}

export function getDining(city: string): Dining[] {
  return cityDining[city] ?? genericDining;
}

export function getHotels(city: string): Hotel[] {
  return cityHotels[city] ?? genericHotels;
}

export function findDestination(name: string): Destination | undefined {
  return destinations.find((d) => d.name === name || d.nameEn.toLowerCase() === name.toLowerCase());
}

