// 交通方式模板
export function makeTransport(from: string, to: string, idx: number): {
  from: string;
  to: string;
  method: string;
  duration: string;
  cost: number;
} {
  const methods = [
    { method: "地铁", duration: "约20分钟", cost: 8 },
    { method: "公交", duration: "约30分钟", cost: 5 },
    { method: "打车", duration: "约15分钟", cost: 45 },
    { method: "步行", duration: "约10分钟", cost: 0 },
    { method: "地铁换乘", duration: "约35分钟", cost: 12 },
  ];
  const m = methods[idx % methods.length];
  return { from, to, method: m.method, duration: m.duration, cost: m.cost };
}
